+#[allow(clippy::cast_precision_loss)]
+fn ratio_pct(numerator: usize, denominator: usize) -> f64 {
+    if denominator == 0 {
+        return 0.0;
+    }
+    (numerator as f64 / denominator as f64) * 100.0
+}
